import React, { useState } from 'react';

function Node({ node, depth, open, toggle }) {
  const pad = { paddingLeft: depth * 16 };
  if (node.type === 'file') {
    return <div style={{ ...pad, padding: '3px 0', paddingLeft: depth * 16 }}>📄 {node.name}</div>;
  }
  const isOpen = open.has(node.id);
  return (
    <div>
      <div
        onClick={() => toggle(node.id)}
        style={{ paddingLeft: depth * 16, padding: '3px 0', cursor: 'pointer', userSelect: 'none', fontWeight: 600 }}
      >
        <span style={{ paddingLeft: depth * 16 }}>{isOpen ? '📂' : '📁'} {node.name}</span>
      </div>
      {isOpen &&
        node.children.map((c) => (
          <Node key={c.id} node={c} depth={depth + 1} open={open} toggle={toggle} />
        ))}
    </div>
  );
}

export default function FileExplorer({ tree }) {
  const [open, setOpen] = useState(() => new Set(['root']));

  const toggle = (id) =>
    setOpen((s) => {
      const n = new Set(s);
      if (n.has(id)) n.delete(id);
      else n.add(id);
      return n;
    });

  return (
    <div style={{ maxWidth: 360, lineHeight: 1.4 }}>
      <Node node={tree} depth={0} open={open} toggle={toggle} />
    </div>
  );
}

