import { Component, Input, Output, EventEmitter } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface FsNode { id: string; name: string; type: 'folder' | 'file'; children?: FsNode[]; }

@Component({
  selector: 'app-tree',
  template: `
    <div>
      <div
        *ngIf="node.type === 'folder'"
        (click)="toggle.emit(node.id)"
        [style.padding-left.px]="depth * 16"
        style="padding-top: 3px; padding-bottom: 3px; cursor: pointer; user-select: none; font-weight: 600;"
      >
        {{ open.has(node.id) ? '📂' : '📁' }} {{ node.name }}
      </div>
      <div
        *ngIf="node.type === 'file'"
        [style.padding-left.px]="depth * 16"
        style="padding-top: 3px; padding-bottom: 3px; user-select: none;"
      >
        📄 {{ node.name }}
      </div>

      <ng-container *ngIf="node.type === 'folder' && open.has(node.id)">
        <app-tree
          *ngFor="let c of node.children"
          [node]="c"
          [open]="open"
          [depth]="depth + 1"
          (toggle)="toggle.emit($event)"
        ></app-tree>
      </ng-container>
    </div>
  `,
})
export class TreeComponent {
  @Input() node!: FsNode;
  @Input() open!: Set<string>;
  @Input() depth = 0;
  @Output() toggle = new EventEmitter<string>();
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>File Explorer Demo</h1>
      <div style="max-width: 360px; line-height: 1.4;">
        <app-tree [node]="tree" [open]="open" [depth]="0" (toggle)="onToggle($event)"></app-tree>
      </div>
    </div>
  `,
})
export class AppComponent {
  open = new Set<string>(['root']);
  tree: FsNode = {
    id: 'root',
    name: 'project',
    type: 'folder',
    children: [
      {
        id: 'src',
        name: 'src',
        type: 'folder',
        children: [
          { id: 'app', name: 'app.component.ts', type: 'file' },
          { id: 'main', name: 'main.ts', type: 'file' },
          {
            id: 'comp',
            name: 'components',
            type: 'folder',
            children: [
              { id: 'btn', name: 'button.component.ts', type: 'file' },
              { id: 'card', name: 'card.component.ts', type: 'file' },
            ],
          },
        ],
      },
      { id: 'pkg', name: 'package.json', type: 'file' },
      { id: 'readme', name: 'README.md', type: 'file' },
    ],
  };

  onToggle(id: string): void {
    if (this.open.has(id)) {
      this.open.delete(id);
    } else {
      this.open.add(id);
    }
  }
}

@NgModule({
  declarations: [AppComponent, TreeComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
